const now = new Date();
const start = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0,0,0,0);
const end = new Date(start.getTime() + 24*3600*1000);
const P='AGILE-24-10-01', T='E-1R-AGILE-24-10-01-C';
msg.method='GET';
msg.url=`https://api.octopus.energy/v1/products/${P}/electricity-tariffs/${T}/standard-unit-rates/`+`?period_from=${start.toISOString()}&period_to=${end.toISOString()}&page_size=100`;
return msg;

const rates = (msg.payload && msg.payload.results) || [];
if (!rates.length) { node.warn('Octopus: no rates returned'); node.status({fill:'red',shape:'ring',text:'no rates'}); return null; }
const N = 6;
const byPrice = [...rates].sort((a,b)=> a.value_inc_vat - b.value_inc_vat);
const cheapest = byPrice.slice(0,N).map(r=>({from:r.valid_from, to:r.valid_to, price:r.value_inc_vat}));
flow.set('cheapestSlots', cheapest);
const ordered = [...cheapest].sort((a,b)=>Date.parse(a.from)-Date.parse(b.from));
const fmt = s => new Date(s.from).toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'});
node.status({fill:'green',shape:'dot',text:`${N} slots, ${ordered.map(fmt).join(',')}`});
node.warn('Octopus cheapest '+N+' slots: '+ordered.map(s=>fmt(s)+'='+s.price.toFixed(2)+'p').join(', '));
return null;

const slots = flow.get('cheapestSlots') || [];
const now = Date.now();
const inCheap = slots.some(s => now >= Date.parse(s.from) && now < Date.parse(s.to));
const desired = inCheap ? 'turbo' : 'auto';
if (desired === flow.get('lastMode')) { return null; }
flow.set('lastMode', desired);
node.status({fill: inCheap?'green':'blue', shape:'dot', text: desired+' @ '+new Date().toLocaleTimeString('en-GB')});
msg.payload = { preset_mode: desired };
return msg;
